import { Link, useNavigate } from 'react-router-dom';

export default function Navbar() {
  const navigate = useNavigate();
  const user = (() => { try { return JSON.parse(localStorage.getItem('user') || '{}'); } catch { return {}; } })();

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <nav style={{
      position: 'sticky', top: 0, zIndex: 100,
      background: 'rgba(0,0,0,0.9)',
      backdropFilter: 'blur(20px)',
      WebkitBackdropFilter: 'blur(20px)',
      borderBottom: '1px solid rgba(255,255,255,0.08)',
      padding: '0 2.5rem',
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      height: '62px',
      fontFamily: "-apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif",
    }}>
      {/* Logo */}
      <Link to="/home" style={{ fontWeight: 700, fontSize: '1.25rem', color: '#fff', textDecoration: 'none', letterSpacing: '-0.5px' }}>
        Nex<span style={{ color: '#D4AF37' }}>Event</span>
      </Link>

      {/* Links */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '2.5rem' }}>
        {[
          { to: '/home', label: 'Home' },
          { to: '/my-bookings', label: 'My Bookings' },
          { to: '/suggest-event', label: 'Suggest', gold: true },
        ].map(({ to, label, gold }) => (
          <Link key={to} to={to} style={{ color: '#A0A0A0', textDecoration: 'none', fontSize: '0.88rem', fontWeight: 500 }}
            onMouseEnter={e => e.target.style.color = gold ? '#D4AF37' : '#ffffff'}
            onMouseLeave={e => e.target.style.color = '#A0A0A0'}>
            {label}
          </Link>
        ))}
      </div>

      {/* Right */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '1.2rem' }}>
        <span style={{ color: '#fff', fontSize: '0.85rem', fontWeight: 600 }}>
          {user?.name || user?.email?.split('@')[0] || 'User'}
        </span>
        <button onClick={logout} style={{
          background: 'transparent', border: '1px solid rgba(255,255,255,0.12)',
          color: '#A0A0A0', borderRadius: '8px', padding: '7px 18px',
          cursor: 'pointer', fontSize: '0.82rem', fontWeight: 500,
          fontFamily: 'inherit', transition: 'all 0.2s',
        }}
          onMouseEnter={e => { e.currentTarget.style.borderColor = '#D4AF37'; e.currentTarget.style.color = '#D4AF37'; }}
          onMouseLeave={e => { e.currentTarget.style.borderColor = 'rgba(255,255,255,0.12)'; e.currentTarget.style.color = '#A0A0A0'; }}>
          Sign Out
        </button>
      </div>
    </nav>
  );
}
